/**
 * POST /api/concierge/send-proactive
 *
 * Sends a proactive outbound message from the member's personal concierge.
 * Called by the proactive cron or by staff triggering a nudge.
 *
 * Body: { club_id, member_id, outreach_type, context }
 *
 * The message is generated by Claude using the member's concierge prompt +
 * outreach context. Sent via the member's preferred channel (SMS/email).
 */
import { sql } from '@vercel/postgres';
import { withAuth, getReadClubId } from '../lib/withAuth.js';
import { buildConciergePrompt } from '../../src/config/conciergePrompt.js';
import { getAnthropicClient, MANAGED_AGENT_ID } from '../agents/managed-config.js';

const OUTREACH_INSTRUCTIONS = {
  re_engagement: `You are reaching out proactively because this member hasn't visited the club recently.
Your tone should be warm, not pushy. Reference something specific they enjoy (their usual tee time,
favorite dining spot, upcoming events they'd like). Make it easy to say yes with a specific suggestion.
Keep it under 200 characters for SMS. Do NOT mention health scores or risk levels.`,

  post_complaint_followup: `You are following up on a complaint this member filed a few days ago.
Be genuinely empathetic — acknowledge the issue without being defensive. Ask if things have improved.
Offer to help with anything else. Keep it under 200 characters for SMS.
Do NOT mention internal tracking or agent systems.`,

  weather_suggestion: `Tomorrow's weather is perfect for golf. You're reaching out to suggest a tee time.
Reference the member's usual playing pattern if known. Make it feel like a friendly insider tip,
not a marketing message. Keep it under 200 characters for SMS.`,

  event_recommendation: `There's an upcoming event that matches this member's interests.
Mention the specific event, date, and why you think they'd enjoy it. Reference household members
if the event is family-friendly. Keep it under 200 characters for SMS.`,

  birthday: `Today is or was recently this member's birthday. Send warm wishes and offer something
special — a complimentary drink at the Grill Room, a preferred tee time, etc. Keep it personal
and brief. Keep it under 200 characters for SMS.`,
};

async function loadMemberForOutreach(clubId, memberId) {
  try {
    const result = await sql`
      SELECT m.member_id::text, m.first_name, m.last_name, m.email, m.phone,
             m.membership_type, m.preferred_channel,
             s.preferences_cache, s.conversation_summary
      FROM members m
      LEFT JOIN member_concierge_sessions s ON s.member_id = m.member_id AND s.club_id = m.club_id
      WHERE m.member_id = ${memberId} AND m.club_id = ${clubId}
    `;
    if (!result.rows.length) return null;
    const m = result.rows[0];
    return {
      member_id: m.member_id,
      name: `${m.first_name} ${m.last_name}`.trim(),
      first_name: m.first_name,
      email: m.email,
      phone: m.phone,
      membership_type: m.membership_type,
      preferred_channel: m.preferred_channel || 'sms',
      preferences: m.preferences_cache ? (typeof m.preferences_cache === 'string' ? JSON.parse(m.preferences_cache) : m.preferences_cache) : null,
      conversation_summary: m.conversation_summary,
    };
  } catch { return null; }
}

async function handler(req, res) {
  if (req.method !== 'POST') return res.status(405).json({ error: 'Method not allowed' });

  const clubId = getReadClubId(req);
  const { member_id, outreach_type, context } = req.body;

  if (!member_id) return res.status(400).json({ error: 'member_id is required' });
  if (!outreach_type) return res.status(400).json({ error: 'outreach_type is required' });

  const profile = await loadMemberForOutreach(clubId, member_id);
  if (!profile) return res.status(404).json({ error: `Member ${member_id} not found` });

  // Get club name
  let clubName = 'Pinetree Country Club';
  try {
    const club = await sql`SELECT name FROM club WHERE club_id = ${clubId}`;
    clubName = club.rows[0]?.name || clubName;
  } catch {}

  // Build the proactive prompt
  const basePrompt = buildConciergePrompt(profile, clubName);
  const outreachInstruction = OUTREACH_INSTRUCTIONS[outreach_type] || OUTREACH_INSTRUCTIONS.re_engagement;
  const contextStr = context ? `\n\nAdditional context: ${JSON.stringify(context)}` : '';

  const systemPrompt = `${basePrompt}\n\n--- PROACTIVE OUTREACH MODE ---\n${outreachInstruction}${contextStr}`;

  // Generate message via Claude (or simulation fallback)
  let message;
  const SIMULATION_MODE = !MANAGED_AGENT_ID;

  if (SIMULATION_MODE) {
    // Simulation: generate a template-based message
    const name = profile.first_name;
    const prefs = profile.preferences || {};
    switch (outreach_type) {
      case 're_engagement':
        message = prefs.teeWindows
          ? `Hi ${name}! Haven't seen you in a bit — your ${prefs.teeWindows} slot is open this week. Want me to book it?`
          : `Hi ${name}! We miss seeing you at the club. Any interest in a round this week? I can find you a great time.`;
        break;
      case 'post_complaint_followup':
        message = `Hi ${name}, I wanted to check in after your recent experience. Has everything improved? I'm here if you need anything at all.`;
        break;
      case 'weather_suggestion':
        message = `Hi ${name}! Tomorrow's looking beautiful — ${context?.weather?.temp || 75}°F and clear. Want me to grab your usual tee time?`;
        break;
      case 'event_recommendation':
        message = `Hi ${name}! The ${context?.event_name || 'Wine Dinner'} is coming up and I thought of you. Want me to RSVP?`;
        break;
      case 'birthday':
        message = `Happy birthday, ${name}! 🎂 We'd love to treat you to a round on the house this week. When works best?`;
        break;
      default:
        message = `Hi ${name}! Just checking in — anything I can help with at the club?`;
    }
  } else {
    try {
      const client = getAnthropicClient();
      const result = await client.messages.create({
        model: 'claude-sonnet-4-20250514',
        max_tokens: 300,
        system: systemPrompt,
        messages: [{ role: 'user', content: `Generate a proactive ${outreach_type} message for this member. Be warm, specific, and brief.` }],
      });
      message = result.content?.find(c => c.type === 'text')?.text || '';
    } catch (err) {
      console.error('Proactive message generation error:', err);
      message = `Hi ${profile.first_name}! Just checking in — anything I can help with at the club?`;
    }
  }

  // Log the outreach
  try {
    await sql`
      INSERT INTO activity_log (club_id, member_id, member_name, action_type, action_subtype, detail, created_at)
      VALUES (${clubId}, ${member_id}, ${profile.name}, 'concierge_proactive', ${outreach_type}, ${message.slice(0, 500)}, NOW())
    `;
  } catch {}

  return res.status(200).json({
    member_id,
    member_name: profile.name,
    channel: profile.preferred_channel,
    outreach_type,
    message,
    simulated: SIMULATION_MODE,
    generated_at: new Date().toISOString(),
  });
}

export default withAuth(handler, { allowDemo: true });
